function kthSmallestPrimeFraction(arr, k) {
    const pq = new PriorityQueue((a, b) => arr[a[0]] * arr[b[1]] - arr[a[1]] * arr[b[0]]);

    for (let i = 0; i < arr.length - 1; i++) {
        pq.offer([i, arr.length - 1]);
    }

    for (let i = 1; i < k; i++) {
        const curr = pq.poll();
        curr[1]--;
        if (curr[0] < curr[1]) {
            pq.offer(curr);
        }
    }

    return [arr[pq.peek()[0]], arr[pq.peek()[1]]];
}

class PriorityQueue {
    constructor(compareFn) {
        this.elements = [];
        this.compareFn = compareFn;
    }

    offer(element) {
        this.elements.push(element);
        this._bubbleUp(this.elements.length - 1);
    }

    poll() {
        const first = this.elements[0];
        const last = this.elements.pop();
        if (this.elements.length > 0) {
            this.elements[0] = last;
            this._trickleDown(0);
        }
        return first;
    }

    peek() {
        return this.elements[0];
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.compareFn(this.elements[index], this.elements[parentIndex]) < 0) {
                [this.elements[index], this.elements[parentIndex]] = [this.elements[parentIndex], this.elements[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _trickleDown(index) {
        while (index < this.elements.length) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;

            if (leftChildIndex >= this.elements.length) {
                break;
            }

            let minChildIndex = this.compareFn(
                this.elements[leftChildIndex],
                this.elements[rightChildIndex]) < 0 ? leftChildIndex : rightChildIndex;

            if (this.compareFn(this.elements[index], this.elements[minChildIndex]) > 0) {
                [this.elements[index], this.elements[minChildIndex]] = [this.elements[minChildIndex], this.elements[index]];
                index = minChildIndex;
            } else {
                break;
            }
        }
    }
}
```

    The algorithm uses a min-priority queue to efficiently select the k-th smallest fraction. The queue is initialized with elements representing fractions, each made of two indices `(i, j)` pointing to the sorted array `arr`. The `compare` function is used to order the elements in the priority queue, comparing the product of the cross-multiplication for pairs representing fractions.

1. Create the priority queue and push `(i, arr.length - 1)` for every `i` between `0` and `arr.length - 2`. The index `i` starts from `0`, and `j` starts as `arr.length - 1`.
2. Pop elements from the priority queue `k-1` times, decrementing the second index (`j`) to consider the next smallest fraction involving the numerator `arr[i]`.
3. After popping `k-1` elements, the top element of the priority queue will now represent the k-th smallest fraction. Return the corresponding elements from the sorted array `arr` using the indices `i` and `j`.

The time complexity of this algorithm is O(k * log(n)), where n is the length of the array `arr`, as the priority queue may have at most n-1 elements and we perform k pops and pushes.

